---buff表现管理
---@class LBattleViewBuffActMgr
local LBattleViewBuffActMgr = classX("LBattleViewBuffActMgr",nil)

local LBattleViewBuffActQueue = require("LApp.gameplay.videobattle.view.obj.LBattleViewBuffActQueue")

function LBattleViewBuffActMgr:ctor()
    ---@type LBattleViewMgr
    self._viewMgr = nil

    ---@type table<number,LBattleViewBuffActQueue[]>
    self._actQueueArrayMap = {}

    ---正在运行时
    ---@type LBattleViewBuffActQueue[]
    self._runningList = {}

    ---@type LBattleBuffActPosition[]
    self._buffPositionList = {}
end

function LBattleViewBuffActMgr:Initialize()

end

function LBattleViewBuffActMgr:SetViewMgr(viewMgr)
    self._viewMgr = viewMgr
end


function LBattleViewBuffActMgr:GetBuffActQueue(expressId)
    local actQueue = self._actQueueArrayMap[expressId]

    ---@type LBattleViewBuffActQueue
    local express =nil
    if not actQueue or #actQueue ==0 then
        express = LBattleViewBuffActQueue:new(expressId, self._viewMgr)
        express:Initialize()
    else
        express = table.remove(actQueue)
    end
    express:Preload()

    return express
end


function LBattleViewBuffActMgr:AddRunningActQueue(express)
    table.insert(self._runningList,express)
end

function LBattleViewBuffActMgr:OnUpdate(time, deltaTime)
    local cnt= #self._runningList
    for k = cnt ,1,-1 do
        local actQueue = self._runningList[k]
        if actQueue:IsEnd() then
            table.remove(self._runningList,k)
            actQueue:OnPlayEnd()
            self:Recycle(actQueue)
        else
            actQueue:OnUpdate(time, deltaTime)
        end
    end

    cnt = #self._buffPositionList
    if cnt > 0 then
        for k= cnt,1,-1 do
            local value = self._buffPositionList[k]
            value:OnUpdate(time, deltaTime)
            if value:IsEnd() then
                table.remove(self._buffPositionList,k)
            end
        end
    end
end

function LBattleViewBuffActMgr:IsNoBuff()
    return #self._runningList == 0 and #self._buffPositionList == 0
end

function LBattleViewBuffActMgr:ClearRunningActQueue()
    if self._runningList then
        for k,v in ipairs(self._runningList) do
            v:Dispose()
        end
        self._runningList = {}
    end
end

function LBattleViewBuffActMgr:Recycle(actQueue)
    local expressId = actQueue:GetExpressId()
    actQueue:OnRecycle()
    local list = self._actQueueArrayMap[expressId]
    if not list then
        list = {}
    end

    table.insert(list,actQueue)
    self._actQueueArrayMap[expressId] = list
end

function LBattleViewBuffActMgr:Dispose()
    if self._isDisposed then
        return
    end
    if self._actQueueArrayMap then
        for k,v in pairs(self._actQueueArrayMap) do
            for k1 ,v1 in ipairs(v) do
                v1:Dispose()
            end
        end
        self._actQueueArrayMap = nil
    end

    if self._runningList then
        for k,v in ipairs(self._runningList) do
            v:Dispose()
        end
        self._runningList = nil
    end

    table.dispose(self)
    self._isDisposed = true
end

function LBattleViewBuffActMgr:StartPositionAct(para)
    local buffPosition = require("LApp.gameplay.videobattle.view.buffact.LBattleBuffActPosition"):new(self._viewMgr)
    table.insert(self._buffPositionList,buffPosition)
    buffPosition:Start(para)
end


return LBattleViewBuffActMgr